<?php
global $wpdb;

$user = wp_get_current_user();
if (!$user->exists())
    return [];

$query = $wpdb->get_results( "SELECT * FROM notifications WHERE `users` LIKE '%" . $user->ID . "%' ORDER BY `id` DESC" );

$notifications = [];
foreach ( $query as $item ) {
    $read = $item->read !== null ? unserialize($item->read) : [];

    $data = [
		'id'            => $item->id,
		'title'         => $item->title,
		'description'   => $item->content,
        'status'        => in_array($user->ID, $read) ? 1 : 0,
		'date'          => strtotime( $item->created_at ),
		'type'          => $item->type,
	];

	$notifications[] = $data;
} ?>

