<script>
    jQuery(document).ready(function ($) {
        $('body').on('click', '.notification-card', function () {
            let _ = $(this);
            let otherCards = $('.notification-card').not(_);

            <?php if ( wp_is_mobile() ) { ?>
            otherCards.find('.notification-excerpt').addClass('line-clamp-1');
            _.find('.notification-excerpt').removeClass('line-clamp-1');
            <?php } ?>

            _.addClass("before:content-none").removeClass("before:content-['']");
            otherCards.removeAttr('style');

            let color = _.attr('data-color');
            if (color) {
                _.css({
                    borderColor: color,
                    boxShadow: `0px 1.5px 0 0 ${color}`
                });
            }

            let id = _.attr('data-id');
            if (!id) {
                console.error('No data-id found.');
                return;
            }

            let title = _.attr('data-title'),
                content = _.attr('data-content'),
                icon = _.find('.notification-icon').html(),
                date = _.attr('date');

            let details = $(".notification-details");
            details.find('.notification-icon').html(icon);
            details.find('.notification-title').html(title);
            details.find('.notification-content').html(content);
            details.find('.notification-date').html(date);

            $.ajax({
                type: 'POST',
                url: "<?php echo admin_url( 'admin-ajax.php' ) ?>",
                data: {
                    'action': 'v2_ajax_handler',
                    'nonce': "<?php echo wp_create_nonce( 'v2-ajax-nonce' ) ?>",
                    'callback': 'panel_notifications_read',
                    'id': id,
                    'user': <?php echo $user->ID; ?>
                },
                success: function(response) {

                },
                error: function(xhr, status, error) {

                }
            });
        });
    });
</script>